syntax.postgresql:
-- Create a range-partitioned table by date
CREATE TABLE orders (
  id SERIAL,
  user_id INT NOT NULL,
  total NUMERIC(10, 2) NOT NULL,
  created_at TIMESTAMPTZ NOT NULL
) PARTITION BY RANGE (created_at);

-- Create partitions
CREATE TABLE orders_2025_q1 PARTITION OF orders
  FOR VALUES FROM ('2025-01-01') TO ('2025-04-01');

CREATE TABLE orders_2025_q2 PARTITION OF orders
  FOR VALUES FROM ('2025-04-01') TO ('2025-07-01');

CREATE TABLE orders_2025_q3 PARTITION OF orders
  FOR VALUES FROM ('2025-07-01') TO ('2025-10-01');

CREATE TABLE orders_2025_q4 PARTITION OF orders
  FOR VALUES FROM ('2025-10-01') TO ('2026-01-01');

-- Create a list-partitioned table by region
CREATE TABLE orders (
  id SERIAL,
  user_id INT NOT NULL,
  total NUMERIC(10, 2) NOT NULL,
  region VARCHAR(20) NOT NULL
) PARTITION BY LIST (region);

CREATE TABLE orders_asia PARTITION OF orders
  FOR VALUES IN ('KR', 'JP', 'CN', 'SG');

CREATE TABLE orders_europe PARTITION OF orders
  FOR VALUES IN ('DE', 'FR', 'UK', 'NL');

CREATE TABLE orders_americas PARTITION OF orders
  FOR VALUES IN ('US', 'CA', 'BR', 'MX');

-- Default partition for unmatched values
CREATE TABLE orders_other PARTITION OF orders DEFAULT;

-- Create a hash-partitioned table
CREATE TABLE orders (
  id SERIAL,
  user_id INT NOT NULL,
  total NUMERIC(10, 2) NOT NULL,
  created_at TIMESTAMPTZ NOT NULL
) PARTITION BY HASH (id);

-- Create 4 hash partitions
CREATE TABLE orders_p0 PARTITION OF orders FOR VALUES WITH (MODULUS 4, REMAINDER 0);
CREATE TABLE orders_p1 PARTITION OF orders FOR VALUES WITH (MODULUS 4, REMAINDER 1);
CREATE TABLE orders_p2 PARTITION OF orders FOR VALUES WITH (MODULUS 4, REMAINDER 2);
CREATE TABLE orders_p3 PARTITION OF orders FOR VALUES WITH (MODULUS 4, REMAINDER 3);

-- Range partition by year, then list sub-partition by region
CREATE TABLE orders (
  id SERIAL,
  user_id INT NOT NULL,
  region VARCHAR(20) NOT NULL,
  created_at TIMESTAMPTZ NOT NULL
) PARTITION BY RANGE (created_at);

-- Create a partition for 2025, sub-partitioned by region
CREATE TABLE orders_2025 PARTITION OF orders
  FOR VALUES FROM ('2025-01-01') TO ('2026-01-01')
  PARTITION BY LIST (region);

CREATE TABLE orders_2025_asia PARTITION OF orders_2025
  FOR VALUES IN ('KR', 'JP', 'CN');

CREATE TABLE orders_2025_europe PARTITION OF orders_2025
  FOR VALUES IN ('DE', 'FR', 'UK');

-- Declarative partitioning (PostgreSQL 10+)
CREATE TABLE orders (
  id SERIAL,
  user_id INT NOT NULL,
  total NUMERIC(10, 2) NOT NULL,
  created_at TIMESTAMPTZ NOT NULL
) PARTITION BY RANGE (created_at);

-- Partitions are managed declaratively
CREATE TABLE orders_2025_q1 PARTITION OF orders
  FOR VALUES FROM ('2025-01-01') TO ('2025-04-01');

-- Attach an existing table as a partition
ALTER TABLE orders ATTACH PARTITION orders_archive
  FOR VALUES FROM ('2020-01-01') TO ('2025-01-01');

-- Detach a partition
ALTER TABLE orders DETACH PARTITION orders_2025_q1;

syntax.mysql:
-- Declarative partitioning in MySQL
CREATE TABLE orders (
  id INT AUTO_INCREMENT,
  user_id INT NOT NULL,
  total DECIMAL(10, 2) NOT NULL,
  created_at DATETIME NOT NULL,
  PRIMARY KEY (id, created_at)
) PARTITION BY RANGE (YEAR(created_at)) (
  PARTITION p2024 VALUES LESS THAN (2025),
  PARTITION p2025 VALUES LESS THAN (2026),
  PARTITION p_future VALUES LESS THAN MAXVALUE
);

-- Add a new partition
ALTER TABLE orders ADD PARTITION (PARTITION p2026 VALUES LESS THAN (2027));

-- Drop a partition (deletes its data)
ALTER TABLE orders DROP PARTITION p2024;

